const rawBaseUrl =
  process.env.PUBLIC_DEPLOYMENT_URL ||
  process.env.DEPLOYMENT_URL ||
  process.argv[2];

const publicRoutes = [
  '/',
  '/privacy/',
  '/terms/',
  '/login/',
  '/signup/?redirect=%2Fjoin%3Frole%3Dparent',
  '/forgot-password/?redirect=%2Fjoin%3Frole%3Dparent',
  '/reset-password/?redirect=%2Fjoin%3Frole%3Dparent',
  '/join/?role=parent',
];

const rejectedBodyMarkers = [
  'Authentication Required',
  'Create Next App',
  'Generated by create next app',
  'To get started, edit the page.tsx file.',
];

function getDeploymentOrigin(value) {
  const trimmed = value?.trim();
  if (!trimmed) {
    throw new Error(
      'Set PUBLIC_DEPLOYMENT_URL or pass a deployment URL, for example: PUBLIC_DEPLOYMENT_URL=https://session-planner.vercel.app npm run smoke:deployment'
    );
  }

  const parsed = new URL(trimmed);
  if (parsed.protocol !== 'http:' && parsed.protocol !== 'https:') {
    throw new Error('PUBLIC_DEPLOYMENT_URL must use http or https.');
  }

  return parsed.origin;
}

function routeUrl(origin, route) {
  return new URL(route, origin).toString();
}

function assertSessionPlannerHtml(route, body) {
  for (const marker of rejectedBodyMarkers) {
    if (body.includes(marker)) {
      throw new Error(`${route} rendered ${JSON.stringify(marker)} instead of the Session Planner app.`);
    }
  }

  if (!body.includes('Session Planner')) {
    throw new Error(`${route} did not render Session Planner content.`);
  }
}

async function assertPublicRoute(origin, route) {
  const response = await fetch(routeUrl(origin, route), { redirect: 'follow' });
  const body = await response.text();

  if (response.status !== 200) {
    throw new Error(`${route} expected 200, received ${response.status}.`);
  }

  assertSessionPlannerHtml(route, body);
}

async function assertDashboardRedirect(origin) {
  const response = await fetch(routeUrl(origin, '/dashboard/'), { redirect: 'manual' });
  const location = response.headers.get('location') ?? '';

  if (![307, 308].includes(response.status)) {
    const body = await response.text();
    assertSessionPlannerHtml('/dashboard/', body);
    throw new Error(`/dashboard/ expected 307/308 redirect to login, received ${response.status}.`);
  }

  const parsedLocation = new URL(location, origin);
  if (parsedLocation.pathname !== '/login/' && parsedLocation.pathname !== '/login') {
    throw new Error(`/dashboard/ redirected to ${location}, expected /login/.`);
  }

  if (!parsedLocation.search.includes('redirect=%2Fdashboard%2F')) {
    throw new Error(`/dashboard/ redirect did not preserve the target path: ${location}`);
  }
}

const origin = getDeploymentOrigin(rawBaseUrl);

for (const route of publicRoutes) {
  await assertPublicRoute(origin, route);
}

await assertDashboardRedirect(origin);

console.log(`Remote deployment smoke test passed for ${origin} (${publicRoutes.length} public routes).`);
